// 1. Captura e Limpeza do JSON original do Gemini
const raw = $input.first().json.content.parts[0].text;
let cleaned = raw.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .replace(/^\uFEFF/, '');

let data;
try {
  data = JSON.parse(cleaned);
} catch (e) {
  throw new Error("Erro ao processar JSON do Gemini.");
}

// 2. FUNÇÃO DE LIMPEZA (Remove acentos, espaços e caracteres especiais)
function limparTexto(texto) {
  return texto
    .toString()
    .normalize('NFD')               // Decompõe caracteres acentuados
    .replace(/[\u0300-\u036f]/g, "") // Remove os acentos
    .replace(/[^a-zA-Z0-9\s-_]/g, "") // Remove símbolos (exceto - e _)
    .trim()
    .replace(/\s+/g, '-');          // Troca espaços por hífens
}

// 3. Preparação dos Campos
const categoriaLimpa = limparTexto(data.categoria || 'Outros');
const fluxoOriginal = data.fluxo || 'Saída';
const fluxoLetra = fluxoOriginal.trim().toUpperCase().substring(0, 1); // 'E' ou 'S'
const valor = Number(data.valor) || 0;
const valor_saldo = fluxoLetra === 'S' ? -Math.abs(valor) : Math.abs(valor);

// 4. Data e Hora
const fuso = 'America/Sao_Paulo';
const agora = new Date();
const criadoEm = agora.toLocaleString('pt-BR', { timeZone: fuso });

const dataRef = data.data || agora.toISOString().slice(0, 10);
const dataLimpa = dataRef.replace(/-/g, '');
const horaLimpa = new Date().toLocaleTimeString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false
}).replace(':', '');

// 5. Construção do Nome do Arquivo e Caminho (Tudo Limpo)
const valorParaNome = valor.toFixed(2).replace('.', '-');
const nomeArquivo = `${dataLimpa}_${horaLimpa}_${categoriaLimpa}_${valorParaNome}_${fluxoLetra}.md`;

// IMPORTANTE: Use o caminho que o n8n enxerga dentro do container
const PATH_BASE = "/data/obsidian/Financas/Lancamentos";
const fullPath = `${PATH_BASE}/${nomeArquivo}`.trim();

// 6. Conteúdo para o Obsidian (Aqui pode ter acentos e espaços normal)
const conteudoObsidian = `---
descricao: "${data.descricao || ''}"
categoria: "${data.categoria || 'Outros'}"
data: ${dataRef}
valor: ${valor}
valor_saldo: ${valor_saldo}
meio_pagamento: "${data.meio_pagamento || 'Não informado'}"
fluxo: "${fluxoOriginal}"
tags: [Finanças/Lançamento]
criado_em: ${criadoEm}
---
# Registro de Finanças
${data.descricao || ''}`;

return [{
  json: {
    nome_arquivo: nomeArquivo,
    caminho_completo: fullPath,
    conteudo: conteudoObsidian,

    // Dados para o Telegram (o que você quer na mensagem)
    valor: valor,
    data: dataRef,
    descricao: data.descricao || '',
    categoria: data.categoria || 'Outros',
    fluxo: fluxoOriginal,
    meio_pagamento: data.meio_pagamento || 'Não informado'
  }
}];
